#include <stdio.h>
#include <time.h>

void log_error(const char *error_msg) {
    FILE *logfile = fopen("error_log.txt", "a");
    if (logfile == NULL) {
        return;
    }

    time_t now = time(NULL);
    struct tm *t = localtime(&now);

    fprintf(logfile, "[%04d-%02d-%02d %02d:%02d:%02d] Error: %s\n",
            t->tm_year + 1900, t->tm_mon + 1, t->tm_mday,
            t->tm_hour, t->tm_min, t->tm_sec, error_msg);

    fclose(logfile);
}